  ('elementary-6f0ba476-moex-00494', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依所得稅法規定，非中華民國境內居住之個人，於一課稅年度內在中華民國境內居留合計不超過90天者， 其自中華民國境外僱主所取得之勞務報酬，課稅規定為何？', '["屬於中華民國來源所得但免徵我國所得稅", "勞務提供地在境內，該勞務報酬應結算申報", "非屬於中華民國來源所得", "勞務提供地在境內，境外僱主支付之報酬採就源扣繳方式繳稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "e49d673c3881", "answer_pdf_sha1": "ea20f9df0686", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00495', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '宋君為中華民國境內居住之個人，108年7月20日購入房地1間，價格為1,200萬元，111年8月5日出 售該房地價格為1,500萬元，試問宋君出售該房地適用之稅率為多少？', '["15%", "20%", "35%", "45%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "e49d673c3881", "answer_pdf_sha1": "ea20f9df0686", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00496', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '江君在乙公司任職年資12年，於111年8月被資遣，當年度領取資遣費24萬元，試問該筆資遣費，乙 公司應如何列報營利事業所得稅，江君應如何申報綜合所得稅？', '["乙公司申報其他費用24萬元，江君申報退職所得，金額為0元", "乙公司申報其他費用24萬元，江君申報其他所得，金額為24萬元", "乙公司申報薪資費用24萬元，江君申報退職所得，金額為0元", "乙公司申報薪資費用24萬元，江君申報薪資收入，金額為24萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "e49d673c3881", "answer_pdf_sha1": "ea20f9df0686", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00497', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '張君為境內居住者，111年度有關境內外所得以及捐贈資料如下，依所得基本稅額條例規定，何者應計入 張君之基本所得額之項目？', '["投資海外基金當年度獲配股利所得90萬元", "投資境內非新創未上市公司股票交易所得100萬元", "受益人與要保人非屬同一人之人壽保險（94年買入），死亡保險給付3,000 萬元", "捐贈私立學校基金會已申報之現金捐贈扣除額20萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "e49d673c3881", "answer_pdf_sha1": "ea20f9df0686", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00498', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依所得稅法及相關法令規定，營利事業對下列各項對象所為之捐贈，何者其金額受所得額 10%之限制？', '["培養支援運動團隊或運動員", "合於規定之政黨及擬參選人", "財團法人私立學校", "中小企業發展 基金  ⑤對中央主管機關認可之職業或業餘運動業"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "e49d673c3881", "answer_pdf_sha1": "ea20f9df0686", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00499', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依所得稅法規定，應收帳款、應收票據及各項欠款債權逾期幾年，經催收後，未經收取本金或利息者， 得視為實際發生呆帳損失？', '["1年", "2年", "3年", "4年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "e49d673c3881", "answer_pdf_sha1": "ea20f9df0686", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00500', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依所得稅法規定，總機構在中華民國境外之營利事業，成本費用分攤困難，得向財政部申請核准，以境 內營業收入若干百分比，計算其營利事業所得額，下列敘述何者錯誤？', '["承包營建工程按10%", "提供技術服務按15%", "國際運輸事業按10%", "出租機器設備按15%"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "e49d673c3881", "answer_pdf_sha1": "ea20f9df0686", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00501', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '若A公司於110年5月15日成立，當年度營利事業課稅所得額為新臺幣12萬元，則當年度營利事業所 得稅應納稅額為多少？', '["0萬元", "1萬元", "2萬元", "3萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "e49d673c3881", "answer_pdf_sha1": "ea20f9df0686", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
