  ('elementary-6f0ba476-moex-00503', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-112-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '聯合公司為按一般稅額計算之營業人，其於111年4月15日出租廠辦給B公司收取押金250萬元，設該 年1月1日郵政定期儲金一年期固定利率為1.04%，則依加值型及非加值型營業稅法規定，該公司5月押 金應設算之銷售額為多少元？', '["2,064", "2,167", "2,600", "0"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:40+00:00", "source_pdf_sha1": "e49d673c3881", "answer_pdf_sha1": "ea20f9df0686", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "506", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL)
